   289→export function collectVariables(program: Program): Set<string> {
   290→  const vars = new Set<string>();
   291→
   292→  for (const node of program.statements) {
   293→    switch (node.nodeType) {
   294→      case 'QueryNode':
   295→        vars.add((node as QueryNode).varName);
   296→        break;
   297→      case 'EncodeNode':
   298→        vars.add((node as EncodeNode).outputVar);
   299→        break;
   300→      case 'PathNode':
   301→        vars.add((node as PathNode).outputVar);
   302→        break;
   303→      case 'WeightNode':
   304→        break;
   305→      case 'EnsembleNode':
   306→        vars.add((node as EnsembleNode).outputVar);
